var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"ENG":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐? 여태 경계만 하고 있다고?","JPN":"何？　いまだ警戒しているだけだと？","ENG":"What? You’ve been on guard this whole time?","TWN":"什麼？到現在都只有戒備？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"방위 부대는? 상부에서 진압 명령을 내리지 않았단 건가?","JPN":"防衛部隊は？　上層部で鎮圧命令を出していないのか？","ENG":"What about the Defense Unit? Didn’t the higher ups order for everything to be suppressed?","TWN":"防衛隊呢？上頭沒有下令鎮壓嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"그, 그게……. 영상으로 녹화된 성명서가 왔다고 합니다.","JPN":"そ、それが……声明を撮影した動画が届いたらしいです。","ENG":"Uh, Well... We received a video message.","TWN":"那個……我們收到一支聲明影片。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤. 잘나신 나리들께 이렇게 뻗댈 날이 올 줄은 몰랐는데.","JPN":"へ、へへ。お偉いさんにこうやって手向かう日が来るとはな。","ENG":"Heh, heh heh. I never imagined the day would come where I could give those higher ups a piece of my mind.","TWN":"嘿嘿嘿，各位大人好，沒想到會有向各位喊話的一天。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"방금 위력 봤지? 첫 발은 시외에 쐈지만 다음에는 댁들 머리 위로 떨어질 거야.","JPN":"今の威力、見ただろ？　一発目は市外の方に撃ったけど、次からはアンタらの頭の上に落ちるぞ。","ENG":"You all saw how powerful that was? The first shot was shot outside city limits on purpose, but next time it’ll fall right on top of you.","TWN":"你們有見識到剛才的威力吧？第一發是射在郊區，但下一發就會落在你們的頭上囉！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"자신 있으면 어디 도망쳐 보라고. 헤, 헤헤. 우리 친구들이 지켜보고 있으니까.","JPN":"自信があったら逃げてみろよ。へ、へへ。俺らの仲間が見守ってるからさ。","ENG":"Go ahead. Run away if you think you can get away with it. Heh, heh. My friends will be watching and waiting.","TWN":"想逃的話試試看，嘿嘿嘿，我們的人可是都看著呢！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_A","text":{"KOREA":"……그래서, 대책 마련 중이시라고 합니다.","JPN":"……で、対策を立てている最中のようです。","ENG":"...So, we began working on countermeasures.","TWN":"……所以現在正在研擬對策當中。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"저딴 뻔한 블러프에 겁을 먹었다고?","JPN":"あんな露骨なハッタリに恐れをなしただと？","ENG":"Are you so scared of such an obvious bluff?","TWN":"對方很明顯是在虛張聲勢，結果你們這樣就怕成這樣？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이 머저리들 같으니……! 이러니 사이비 같은 소리에 놀아나지!","JPN":"このアホどもが……！　これだからインチキに好き勝手に振り回されるのだろうが！","ENG":"You idiots...! Paying so much attention to stuff like this!","TWN":"愚蠢的東西……！你們就是這樣才會被那番鬼話給耍得團團轉！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……이 번호는 외부에 공개된 적 없다. 누구냐.","JPN":"……この番号は外部に公開されたことがない番号だぞ。誰だ。","ENG":"...This number has never been released to the public. Who is this?","TWN":"……這支電話號碼是沒有對外公開的，會是誰？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"접니다, 국장님.","JPN":"私です。局長。","ENG":"It’s me, Chief.","TWN":"部長，是我。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트……?","JPN":"レヴナント……？","ENG":"Revenant?","TWN":"亡靈……？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"사라지라는 내 말을 벌써 잊었나? 나한테 연락해서 어쩔 셈이야?!","JPN":"消えろと言った私の言葉をもう忘れたのか？　私に連絡してどうするんだ！？","ENG":"Have you already forgotten that I told you to disappear? Why are you contacting me?!","TWN":"我不是叫你消失嗎？你打給我是要做什麼？！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"네. 자수할 생각입니다.","JPN":"はい。自首するつもりです。","ENG":"I’m going to turn myself in.","TWN":"我要自首。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};